CREATE OR REPLACE FUNCTION calc_job_boards_job_listings(p_job_board_id TEXT)
RETURNS INTEGER AS $$
BEGIN
  RETURN ((SELECT COUNT(*) FROM job_listings WHERE job_board = (SELECT NULLIF(job_board_id, '') FROM job_boards WHERE job_board_id = p_job_board_id)));
END;
$$ LANGUAGE plpgsql STABLE SECURITY DEFINER;

