CREATE OR REPLACE FUNCTION calc_score_results_name(p_score_result_id TEXT)
RETURNS TEXT AS $$
BEGIN
  RETURN (CONCAT(calc_score_results_job_listing_name(p_score_result_id), ' - ', calc_score_results_search_run_name(p_score_result_id)))::text;
END;
$$ LANGUAGE plpgsql STABLE SECURITY DEFINER;


