CREATE OR REPLACE FUNCTION calc_decisions_name(p_decision_id TEXT)
RETURNS TEXT AS $$
BEGIN
  RETURN (CONCAT(UPPER((SELECT NULLIF(verdict, '') FROM decisions WHERE decision_id = p_decision_id)), ': ', calc_decisions_job_listing_name(p_decision_id)))::text;
END;
$$ LANGUAGE plpgsql STABLE SECURITY DEFINER;


CREATE OR REPLACE FUNCTION calc_decisions_is_scoring_signal(p_decision_id TEXT)
RETURNS BOOLEAN AS $$
BEGIN
  RETURN (CASE WHEN (SELECT NULLIF(verdict, '') FROM decisions WHERE decision_id = p_decision_id) = 'yes' THEN TRUE ELSE FALSE END)::boolean;
END;
$$ LANGUAGE plpgsql STABLE SECURITY DEFINER;

